                alert(`Cannot load: Version mismatch.\n\nSave: v${info.data.version || '0.1.36'}\nApp: v${VERSION}\n\nPlease start a New Game or use a compatible save.`);
                return;
            }
            onLoadGame(info.data, info.index);
        }
