import { loadFromSlot } from '../../utils/saveSystem';
import ConfirmationModal from './ConfirmationModal';

interface SettingsModalProps {
    isOpen: boolean;
    onClose: () => void;
    onQuit: () => void;
    onLoadRequest: (data: any, depth: number) => void;
}

const SettingsModal: React.FC<SettingsModalProps> = ({ isOpen, onClose, onQuit, onLoadRequest }) => {
    const { state, actions } = useGame();
    const [slModal, setSlModal] = useState<{ isOpen: boolean, mode: 'SAVE' | 'LOAD' }>({ isOpen: false, mode: 'SAVE' });
    const [loadConfirm, setLoadConfirm] = useState<{ isOpen: boolean, data: any, index: number | null }>({
        isOpen: false,
        data: null,
        index: null
    });

    const APP_VERSION = "0.1.41b";

    if (!isOpen) return null;

    const handleSlotAction = (slotIndex: number) => {
        if (slModal.mode === 'SAVE') {
            actions.saveGame(slotIndex);
        } else {
            const data = loadFromSlot(slotIndex);
            if (data) {
                // 버전 검증 로직 추가
                if (data.version !== APP_VERSION) {
                    actions.showToast(`Load Failed: Version mismatch. (Save: v${data.version || '0.1.36'}, App: v${APP_VERSION})`);
                    return;
                }
                setLoadConfirm({ isOpen: true, data, index: slotIndex });
            }
        }
    };

    const handleConfirmLoad = () => {
        if (loadConfirm.data && loadConfirm.index !== null) {
            setLoadConfirm({ ...loadConfirm, isOpen: false });
            setSlModal({ ...slModal, isOpen: false });
            onClose();
            onLoadRequest(loadConfirm.data, loadConfirm.index);
        }
    };

    const toggleLogTicker = () => {
        actions.updateSettings({ showLogTicker: !state.settings.showLogTicker });
    };

    return (
        <>
            <div className="fixed inset-0 z-[1500] flex items-center justify-center bg-black/90 backdrop-blur-md px-[10%] py-[15%] animate-in fade-in duration-200 overflow-hidden">
                <div className="bg-stone-900 border-2 border-stone-700 rounded-3xl w-[90vw] max-w-[380px] h-fit max-h-full min-h-[200px] min-w-[280px] shadow-2xl flex flex-col overflow-hidden animate-in zoom-in-95 duration-200 mx-auto">

                    {/* Header */}
                    <div className="flex items-center justify-between p-5 border-b border-stone-800 bg-stone-850 shrink-0">
                        <div className="flex items-center gap-3">
                            <Settings className="w-6 h-6 text-amber-500 animate-spin-slow" />
                            <h3 className="font-bold font-serif uppercase tracking-widest text-base text-stone-100">System Menu</h3>
                        </div>
                        <button onClick={onClose} className="p-1.5 hover:bg-stone-800 rounded-full text-stone-500 transition-colors"><X className="w-6 h-6" /></button>
                    </div>

                    {/* Menu List */}
                    <div className="flex-1 p-5 space-y-6 overflow-y-auto custom-scrollbar">
                        {/* Data Management */}
                        <div className="space-y-2">
                            <h4 className="text-[9px] font-black text-stone-500 uppercase tracking-widest px-1">Persistence</h4>
                            <div className="space-y-2">
                                {[
                                    { label: 'Save Progress', icon: <Save className="w-5 h-5" />, action: () => setSlModal({ isOpen: true, mode: 'SAVE' }) },
                                    { label: 'Load Data', icon: <Upload className="w-5 h-5" />, action: () => setSlModal({ isOpen: true, mode: 'LOAD' }) }
                                ].map((item, idx) => (
                                    <button
                                        key={idx}
                                        onClick={item.action}
                                        className="w-full flex items-center gap-4 p-4 rounded-xl border border-stone-700 bg-stone-800 hover:border-amber-500 hover:bg-stone-750 text-stone-300 transition-all"
                                    >
                                        <div className="text-amber-500">{item.icon}</div>
                                        <span className="font-black text-xs uppercase tracking-widest">{item.label}</span>
                                    </button>
                                ))}
                            </div>
                        </div>

                        {/* Game Preferences */}
                        <div className="space-y-2">
                            <h4 className="text-[9px] font-black text-stone-500 uppercase tracking-widest px-1">Preferences</h4>
                            <div className="bg-stone-800 border border-stone-700 rounded-xl p-4 flex items-center justify-between group cursor-pointer hover:border-stone-500 transition-all" onClick={toggleLogTicker}>
                                <div className="flex items-center gap-3">
                                    <Layout className="w-5 h-5 text-indigo-400" />
                                    <div className="flex flex-col">
                                        <span className="font-black text-xs uppercase tracking-widest text-stone-200">Header Logs</span>
                                        <span className="text-[9px] text-stone-500 uppercase font-bold">Show/Hide Log Ticker Row</span>
                                    </div>
                                </div>
                                <div className={`w-10 h-6 rounded-full p-1 transition-all duration-300 ${state.settings.showLogTicker ? 'bg-amber-600' : 'bg-stone-900 border border-stone-700'}`}>
                                    <div className={`w-4 h-4 bg-white rounded-full shadow-md transition-all duration-300 ${state.settings.showLogTicker ? 'translate-x-4' : 'translate-x-0'}`} />
                                </div>
                            </div>
                        </div>

                        {/* Exit */}
                        <div className="pt-2">
                            <button
                                onClick={onQuit}
                                className="w-full flex items-center gap-4 p-4 rounded-xl border border-stone-700 bg-stone-800 hover:border-red-500 hover:bg-red-950/20 text-stone-300 transition-all"
                            >
                                <div className="text-red-500"><LogOut className="w-5 h-5" /></div>
                                <span className="font-black text-xs uppercase tracking-widest">Quit to Title</span>
                            </button>
                        </div>
                    </div>

                    {/* Footer */}
                    <div className="p-3 bg-stone-950 text-center border-t border-stone-800 shrink-0">
                        <span className="text-[10px] text-stone-600 font-mono uppercase tracking-[0.2em]">Build v{APP_VERSION}</span>
                    </div>
                </div>
            </div>

            <SaveLoadModal 
                isOpen={slModal.isOpen}
                mode={slModal.mode}
                onClose={() => setSlModal({ ...slModal, isOpen: false })}
                onAction={handleSlotAction}
            />

            <ConfirmationModal 
                isOpen={loadConfirm.isOpen}
                title="Overwrite Progress?"
                message="Loading this file will discard any unsaved progress in your current session. Do you wish to continue?"
                confirmLabel="Confirm Load"
                onConfirm={handleConfirmLoad}
                onDelete={() => {}} // Not used here but matches props
                onCancel={() => setLoadConfirm({ ...loadConfirm, isOpen: false })}
            />
        </>
    );
};

export default SettingsModal;

import { GameState } from '../types/game-state';

const SAVE_PREFIX = 'lockharts_forge_slot_';
const META_KEY = 'lockharts_forge_save_metadata';
const APP_VERSION = '0.1.41b';

export interface SaveMetadata {
    index: number;
    timestamp: number;
    day: number;
    gold: number;
    label: string;
    version: string;
}

export const getSaveMetadataList = (): SaveMetadata[] => {
    try {
        const metaData = localStorage.getItem(META_KEY);
        if (!metaData) return [];
        const parsed = JSON.parse(metaData);
        // CRITICAL: metaList.map is not a function 에러 방지를 위해 배열인지 확인
        return Array.isArray(parsed) ? parsed : [];
    } catch {
        return [];
    }
};

export const getNextAvailableSlot = (): number => {
    const metaList = getSaveMetadataList();
    const usedIndices = metaList.map(m => m.index);
    for (let i = 0; i < 3; i++) {
        if (!usedIndices.includes(i)) return i;
    }
    return 0; // 모두 차있으면 첫 번째 슬롯 리턴
};

export const saveToSlot = (slotIndex: number, state: GameState) => {
    try {
        const dataToSave = {
            ...state,
            version: APP_VERSION, // 데이터 본체에 버전 정보 추가
            activeEvent: null,
            showSleepModal: false,
            showJournal: false,
            isCrafting: false,
            lastCraftedItem: null
        };

        // 1. Save main data
        localStorage.setItem(`${SAVE_PREFIX}${slotIndex}`, JSON.stringify(dataToSave));

        // 2. Update metadata
        const currentMeta = getSaveMetadataList();
        const newMeta: SaveMetadata = {
            index: slotIndex,
            timestamp: Date.now(),
            day: state.stats.day,
            gold: state.stats.gold,
            label: `Slot ${slotIndex + 1}`,
            version: APP_VERSION
        };

        const filteredMeta = currentMeta.filter(m => m.index !== slotIndex);
        filteredMeta.push(newMeta);
        filteredMeta.sort((a, b) => b.timestamp - a.timestamp); // 최근순 정렬

        localStorage.setItem(META_KEY, JSON.stringify(filteredMeta));
        return true;
    } catch (err) {
        console.error('Failed to save to slot:', err);
        return false;
    }
};

// 특정 슬롯을 지정하지 않았을 때 사용하는 기본 저장 (이제 context에서 관리됨)
export const saveToStorage = (state: GameState) => {
    return saveToSlot(0, state);
};

export const loadFromSlot = (slotIndex: number): (GameState & { version?: string }) | null => {
    try {
        const data = localStorage.getItem(`${SAVE_PREFIX}${slotIndex}`);
        return data ? JSON.parse(data) : null;
    } catch {
        return null;
    }
};

// 불러올 때 마지막 저장된 데이터와 그 인덱스를 함께 리턴하는 헬퍼
export const getLatestSaveInfo = (): { data: GameState & { version?: string }, index: number } | null => {
    const meta = getSaveMetadataList();
    if (meta.length === 0) return null;
    const index = meta[0].index;
    const data = loadFromSlot(index);
    return data ? { data, index } : null;
};

export const loadFromStorage = (): GameState | null => {
    const info = getLatestSaveInfo();
    return info ? info.data : null;
};

export const deleteSlot = (slotIndex: number) => {
    localStorage.removeItem(`${SAVE_PREFIX}${slotIndex}`);
    const meta = getSaveMetadataList().filter(m => m.index !== slotIndex);
    localStorage.setItem(META_KEY, JSON.stringify(meta));
};

const VERSION_MARKER_KEY = 'lockharts_forge_version_marker';
const SAVE_PREFIX = 'lockharts_forge_slot_';

/**
 * 웹 환경의 캐시와 로컬 저장소를 관리하고 초기화합니다.
 * 세이브 데이터를 보존하면서 오래된 에셋이나 잘못된 상태값을 정리합니다.
 * 프리뷰 환경에서의 안정성을 위해 metadata.json을 fetch로 로드합니다.
 */
export const initializeWebCache = async (): Promise<void> => {
    let currentVersion = '0.1.41b'; // 기본값

    try {
        // 프리뷰 환경 도메인 문제를 피하기 위해 런타임에 상대 경로로 가져옵니다.
        const response = await fetch('./metadata.json');
        if (response.ok) {
            const metadata = await response.json();
            currentVersion = metadata.version;
        }
    } catch (e) {
        console.warn("[System] Could not fetch metadata.json, using default version.");
    }

    console.group(`[System] Initializing Web Cache (v${currentVersion})`);

    try {
        // 1. 브라우저 Cache API 정리 (Service Worker 에셋 등)
        if ('caches' in window) {
            const cacheNames = await caches.keys();
            await Promise.all(cacheNames.map(name => caches.delete(name)));
            if (cacheNames.length > 0) {
                console.log(`- Cleared ${cacheNames.length} cache containers.`);
            }
        }

        // 2. 로컬 저장소 버전 체크 및 클린업
        const rawMarker = localStorage.getItem(VERSION_MARKER_KEY);
        let needsCleanup = false;

        if (!rawMarker) {
            needsCleanup = true;
        } else {
            try {
                const marker = JSON.parse(rawMarker);
                if (marker.version !== currentVersion) {
                    needsCleanup = true;
                }
            } catch (e) {
                needsCleanup = true;
            }
        }

        if (needsCleanup) {
            console.log("- Version mismatch or first run. Performing storage maintenance...");

            const keysToRemove: string[] = [];
            for (let i = 0; i < localStorage.length; i++) {
                const key = localStorage.key(i);
                if (!key) continue;

                // 세이브 데이터 슬롯과 버전 마커, D-pad 설정은 보존
                // lockharts_forge_meta (구버전 키)는 정리 대상에 포함시켜 충돌 제거
                const isSaveSlot = key.startsWith(SAVE_PREFIX);
                const isVersionMarker = key === VERSION_MARKER_KEY;
                const isDpadConfig = key.startsWith('dpad_');
                const isSaveMetadata = key === 'lockharts_forge_save_metadata';

                if (!isSaveSlot && !isVersionMarker && !isDpadConfig && !isSaveMetadata) {
                    keysToRemove.push(key);
                }
            }

            keysToRemove.forEach(key => localStorage.removeItem(key));
            if (keysToRemove.length > 0) {
                console.log(`- Removed ${keysToRemove.length} obsolete storage keys.`);
            }

            // 새로운 버전 마커 기록
            localStorage.setItem(VERSION_MARKER_KEY, JSON.stringify({ version: currentVersion, timestamp: Date.now() }));
        }

        console.log("- Web environment is now clean.");
    } catch (error) {
        console.warn("- Cache initialization encountered issues:", error);
    } finally {
        console.groupEnd();
    }
};

